#[test]
fn forbidden_change_blocks_completion() {
    let engine = Lodestar::open_in_memory().unwrap();
    let goal = engine
        .define_goal(
            GoalKind::Invariant,
            "Protect schema",
            "schema cannot change",
            None,
        )
        .unwrap();
    engine
        .link_goal_to_code(
            &goal.id,
            &["artifact:src/schema.sql".into()],
            CodeBindingMode::ForbidChange,
        )
        .unwrap();
    let task = engine.create_task(&goal.id, "inspect schema", "").unwrap();
    engine.claim_task(&task.id, "agent-a", 300).unwrap();
    let claim = engine.store().get_task(&task.id).unwrap().unwrap();
    let evidence = evidence(
        &task.id,
        "agent-a",
        "artifact:src/schema.sql",
        claim.claim_started_at.unwrap(),
    );

    let check = engine.check_conformance(&evidence, Some(&task.id)).unwrap();
    let (completed, result) = engine
        .complete_task(&task.id, "agent-a", &evidence, &check)
        .unwrap();
    assert!(!completed);
    assert_eq!(result.verdict, Verdict::Violation);
    assert_eq!(
        engine.store().get_task(&task.id).unwrap().unwrap().status,
        TaskStatus::Blocked
    );
}

#[test]
fn cross_agent_and_out_of_window_evidence_are_rejected() {
    let engine = Lodestar::open_in_memory().unwrap();
    let goal = engine
        .define_goal(GoalKind::Objective, "Ship auth", "change auth", None)
        .unwrap();
    engine
        .link_goal_to_code(
            &goal.id,
            &["artifact:src/auth.rs".into()],
            CodeBindingMode::Governed,
        )
        .unwrap();
    let task = engine.create_task(&goal.id, "change auth", "").unwrap();
    engine.claim_task(&task.id, "agent-a", 300).unwrap();
    let claim = engine.store().get_task(&task.id).unwrap().unwrap();

    let wrong_agent = evidence(
        &task.id,
        "agent-b",
        "artifact:src/auth.rs",
        claim.claim_started_at.unwrap(),
    );
    assert!(engine
        .check_conformance(&wrong_agent, Some(&task.id))
        .is_err());

    let outside = evidence(
        &task.id,
        "agent-a",
        "artifact:src/auth.rs",
        claim.claim_started_at.unwrap() - 1,
    );
    assert!(engine.check_conformance(&outside, Some(&task.id)).is_err());
    assert_eq!(
        engine.store().get_task(&task.id).unwrap().unwrap().status,
        TaskStatus::Claimed
    );
}

#[test]
fn claim_is_collision_free_across_connections() {
    let path = temp_db("race");
    {
        let engine = Lodestar::open(&path).unwrap();
        let g = engine
            .define_goal(GoalKind::Objective, "Race", "one winner only", None)
            .unwrap();
        let t = engine.create_task(&g.id, "contended", "").unwrap();

        let wins = Arc::new(AtomicUsize::new(0));
        let mut handles = Vec::new();
        for i in 0..8 {
            let path = path.clone();
            let task_id = t.id.clone();
            let wins = Arc::clone(&wins);
            handles.push(std::thread::spawn(move || {
                let e = Lodestar::open(&path).unwrap();
                if e.claim_task(&task_id, &format!("agent-{i}"), 60).unwrap() {
                    wins.fetch_add(1, Ordering::SeqCst);
                }
            }));
        }
        for h in handles {
            h.join().unwrap();
        }
        // Exactly one of eight racing agents may hold the claim.
        assert_eq!(wins.load(Ordering::SeqCst), 1);
    }
    cleanup(&path);
}

#[test]
fn shared_db_is_visible_across_worktree_connections() {
    let path = temp_db("shared");
    {
        // "Worktree A" defines intent...
        let a = Lodestar::open(&path).unwrap();
        let g = a
            .define_goal(GoalKind::Invariant, "Zero token", "no llm on ingest", None)
            .unwrap();
        a.create_task(&g.id, "enforce", "").unwrap();

        // ..."worktree B" (a separate connection) sees it.
        let b = Lodestar::open(&path).unwrap();
        assert_eq!(b.get_constitution().unwrap().len(), 1);
        let next = b.next_task().unwrap().unwrap();
        assert_eq!(next.goal_id, g.id);
    }
    cleanup(&path);
}

#[test]
fn learned_knowledge_loop_promotes_then_advises_conformance_without_violation() {
    let engine = Lodestar::open_in_memory().unwrap();

    // Promotion (ADR-0022): a proven-signal candidate (>= 3 nodes over >= 3 days)
    // clears the existing gate and becomes durable knowledge; a too-thin one does
    // not — the bridge invents no new threshold.
    let promoted = engine
        .promote_signals(&[
            SignalPromotion {
                subject: "artifact:src/lexer.rs".into(),
                evidence_node_ids: vec![
                    "artifact:src/lexer.rs".into(),
                    "execution:a".into(),
                    "execution:b".into(),
                ],
                first_seen: 0,
                last_seen: 10 * 24 * 3600,
                statement: None,
            },
            SignalPromotion {
                subject: "artifact:src/rare.rs".into(),
                evidence_node_ids: vec!["execution:one".into()],
                first_seen: 0,
                last_seen: 5,
                statement: None,
            },
        ])
        .unwrap();
    assert_eq!(promoted.len(), 1);
    assert_eq!(engine.active_knowledge().unwrap().len(), 1);

    // Conformance consumption: an ungoverned change touching the knowledge's node
    // surfaces an advisory finding and is nudged to NeedsHuman — never Violation.
    let evidence = ConformanceEvidence {
        schema_version: 1,
        task_id: None,
        agent_id: "agent-a".into(),
        started_at: 1,
        ended_at: 2,
        changed_node_ids: vec!["artifact:src/lexer.rs".into()],
        failed_node_ids: Vec::new(),
        execution_ids: vec!["execution:proof".into()],
        successful_execution_ids: vec!["execution:proof".into()],
        commit_ids: Vec::new(),
        summary: "touch lexer".into(),
        provenance: vec![
            EvidenceProvenance {
                source_id: "agent:agent-a".into(),
                target_id: "execution:proof".into(),
                relation: "observed".into(),
            },
            EvidenceProvenance {
                source_id: "execution:proof".into(),
                target_id: "artifact:src/lexer.rs".into(),
                relation: "modified".into(),
            },
        ],
    };
    let res = engine.check_conformance(&evidence, None).unwrap();
    assert_eq!(res.verdict, Verdict::NeedsHuman);
    assert_ne!(res.verdict, Verdict::Violation);
    assert!(res
        .findings
        .iter()
        .any(|f| f.contains("advisory: learned knowledge")));
}
